    /**
     * Load surfaced messages from background/cron jobs.
     */
    func loadSurfacedMessages(limit: Int64) throws  -> String
    
    func persistConfig() throws 
    
    /**
     * Refresh an OAuth token.
     */
    func refreshToken(provider: String) throws  -> AuthTokenResult
    
    /**
     * Remove a cron job.
     */
    func removeCronJob(id: String) throws 
    
    /**
     * Remove a cron skill.
